20	const BLOCK_PRICE_FOR_3_ALIKE = 60;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
23	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
24	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
25	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	export function generateQuote(items: Item[], customer: Customer): { basePremium: number } {
29	  const nonCursedCountsByType: Record<string, number> = {};
30	  let cursedPremium = 0;
31	  let enchantmentSurcharge = 0;
32	
33	  for (const item of items) {
34	    const itemBasePremium = BASE_PREMIUMS[item.type];
35	    if (item.cursed) {
36	      cursedPremium += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
37	    } else {
38	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
39	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
40	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
41	      }
42	    }
43	  }
44	
45	  let basePremium = cursedPremium;
46	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
47	    if (count === 3) {
48	      basePremium += BLOCK_PRICE_FOR_3_ALIKE;
49	    } else {
50	      basePremium += count * BASE_PREMIUMS[type];
51	    }
52	  }
53	  basePremium += enchantmentSurcharge;
54	
55	  basePremium *= FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
56	
57	  if (customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS) {
58	    basePremium *= LOYALTY_DISCOUNT_MULTIPLIER;
59	  }
60	
61	  basePremium = Math.round(basePremium * 100) / 100;
62	
63	  return { basePremium };
64	}
